const Q_GEOGRAPHY_1995=[{"id": "objective>Geography>1995>1", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The prismatic compass indicates the positions of objects in relation to the?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">North Star</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Grid North</div>", "<div style=\"font-family:Cambria;font-size:17px;\">True North</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Magnetic North</div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The prismatic compass calculates bearings in whole circle bearing system which determines the angle which the survey line makes with the magnetic north in the clockwise direction. The whole circle bearing ranges from 0 degree to 360 degrees in the clockwise direction.</div>", "topic": "PRATICAL GEOGRAPHY I : INTERPRETATION OF STATISTICAL DATA; MAPS AND DIAGRAMS"}, {"id": "objective>Geography>1995>2", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Temperature is usually depicted by line graph because it is property that?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">fluctuates over space</div>", "<div style=\"font-family:Cambria;font-size:17px;\">varies continuously over time</div>", "<div style=\"font-family:Cambria;font-size:17px;\"> measures sensible heat</div>", "<div style=\"font-family:Cambria;font-size:17px;\">is measured interms of quantity</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Line graph is a line used for data where emphasis is on continuous change i.e varies continuously overtime.In other words, line graph is used to join or connect the highest points of a groupof data such as rainfall,temperature,humidity and other information.</div>", "topic": "PRATICAL GEOGRAPHY I : INTERPRETATION OF STATISTICAL DATA; MAPS AND DIAGRAMS"}, {"id": "objective>Geography>1995>3", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The difference in elevation between the highest and the lowest points in an area is its?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">maximum relief</div>", "<div style=\"font-family:Cambria;font-size:17px;\">relative relief</div>", "<div style=\"font-family:Cambria;font-size:17px;\">vertical interval</div>", "<div style=\"font-family:Cambria;font-size:17px;\">average relief</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The relief of an area refers to the position and character of the highlands and lowlands. The highlands are the highest points while the lowlands are the lowest points in such area. The difference in elevation between the highest and lowest points is the vertical interval.</div>", "topic": "PRATICAL GEOGRAPHY II : LANDFORMS"}, {"id": "objective>Geography>1995>4", "question": "<div style=\"font-family:Cambria;font-size:17px;\">A live broadcast of a football match which starts in Boston, U.S.A. at 11:30 a.m begins in a place located 15°E at 5:30 p.m because Boston lies approximately on longitude?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">105°E</div>", "<div style=\"font-family:Cambria;font-size:17px;\">90°E</div>", "<div style=\"font-family:Cambria;font-size:17px;\">90°W</div>", "<div style=\"font-family:Cambria;font-size:17px;\">75°W</div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">(west--11:30am--Boston(?)) ←substract (East--5:30pm--Place(15<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">o</span>E)) <br/> Boston comes first because 11:30am comes before 5:30pm <br/> Time difference=5:30pm-11:30am=6hours <br/> recall 360<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">o</span>=24hrs <br/> therefore, 6hrs=360 * 6/24=90<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">o</span> <br/>  <br/> since the arrow points towards the question mark, we subtract <br/> 90<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">o</span>-15<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">o</span>=75 <br/> Boston lies in the west, hence its longitude is 75<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">o</span>W</div>", "topic": "HUMAN GEOGRAPHY : POPULATION"}, {"id": "objective>Geography>1995>5", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The features commonly associated with river rejuvenation include knick points?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">paried terrances and entrenched meanders</div>", "<div style=\"font-family:Cambria;font-size:17px;\">unparied terraces and braided channels</div>", "<div style=\"font-family:Cambria;font-size:17px;\">unparied terraces and abandoned meader courses</div>", "<div style=\"font-family:Cambria;font-size:17px;\">paired terraces and abandoned courses</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">If a river on a flood plain is rejuvenated, the resulting vertical erosion by the river produces terraces that are paired.If a meandering river is rejuvenated, the vertical erosion of the river causes the meanders to cut deep into the valley floor. Such meanders are called incised or entrenched meanders</div>", "topic": "PRATICAL GEOGRAPHY II : WATER BODIES"}, {"id": "objective>Geography>1995>6", "question": "<div style=\"font-family:Cambria;font-size:17px;\">When condensation occurs in a rising air mass, latent heat is?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">absorbed by carbon dioxide</div>", "<div style=\"font-family:Cambria;font-size:17px;\">lost to the atmosphere</div>", "<div style=\"font-family:Cambria;font-size:17px;\">stored in the water molecules</div>", "<div style=\"font-family:Cambria;font-size:17px;\">released as sensible heat</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">When air rises, it moves from a zone of dense air on the surface to areas of less dense air in the atmosphere. The rising air thus has less weight above it and the lower pressure allows the air to expand and cool down. The latent heat produced is then absorbed by carbon dioxide in air</div>", "topic": "PRATICAL GEOGRAPHY II : WATER BODIES"}, {"id": "objective>Geography>1995>7", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Two cloud types of great vertical extent that produce much rainfall are?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\"> cumulus and stratus</div>", "<div style=\"font-family:Cambria;font-size:17px;\">cumulus and cumulo-nimbus</div>", "<div style=\"font-family:Cambria;font-size:17px;\">cumulo-nimbus and nimbostratus</div>", "<div style=\"font-family:Cambria;font-size:17px;\">strato-cumulus and nimbo-stratus</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">There are two cloud type of great vertical extent i.e cumulus and cumulo-nimbus.Cumulus is a vertical cloud with with rounded top and horizontal base, typical of humid tropical regions.Cumulonimbus is a cloud of great vertical height.It is a black and white globular mass giving it different shapes. it is frequently seen in tropical afternoons. It is also known as a thunder cloud. <br/> </div>", "topic": "PRATICAL GEOGRAPHY II : WEATHER AND CLIMATE"}, {"id": "objective>Geography>1995>8", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Which of the following statements distinguishes Koppen's Am from his Af climate?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">Rainfall greater than 2000mm</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Location of the tropics</div>", "<div style=\"font-family:Cambria;font-size:17px;\">very short dry season</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Shorter frost season</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">In Koppen's Tropical monsoon climate(Am), there is high annual rainfall of about 1500mm while in his Tropical Rainforest climate(Af), there is high annual rainfall greater than 2000m</div>", "topic": "PRATICAL GEOGRAPHY II : WEATHER AND CLIMATE"}, {"id": "objective>Geography>1995>9", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Use the diagram below to answer the question <br/> <img src=\"data:image/png;base64,\" style=\"position:relative;max-width:100%;\"/> <br/>  <br/> The fault scarp is marked? </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">P</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Q</div>", "<div style=\"font-family:Cambria;font-size:17px;\">R</div>", "<div style=\"font-family:Cambria;font-size:17px;\">S</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">A fault scarp is a small step or offset on the ground surface where one side of a fault has moved vertically with respect to the other. It is the topographic expression of faulting attributed to the displacement of the land surface by movement along faults. R is the fault scarp according to the diagram</div>", "topic": "PRATICAL GEOGRAPHY I : INTERPRETATION OF STATISTICAL DATA; MAPS AND DIAGRAMS"}, {"id": "objective>Geography>1995>10", "question": "<div style=\"font-family:Cambria;font-size:17px;\"> Use the diagram below to answer the question <br/> <img src=\"data:image/png;base64,\" style=\"position:relative;max-width:100%;\"/> <br/> The faults both sides of the horst are?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">normal faults</div>", "<div style=\"font-family:Cambria;font-size:17px;\">reversed faults</div>", "<div style=\"font-family:Cambria;font-size:17px;\">tear faults</div>", "<div style=\"font-family:Cambria;font-size:17px;\">thrust faults</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">If a block of rock between two normal faults rises or the land on either sides of the block subsides, a block mountain or Horst is formed.Hence, the faults on both sides of the horst are normal faults</div>", "topic": "PRATICAL GEOGRAPHY I : INTERPRETATION OF STATISTICAL DATA; MAPS AND DIAGRAMS"}, {"id": "objective>Geography>1995>11", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The thick, scarred barks of many savannah trees are the effect of?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">drought</div>", "<div style=\"font-family:Cambria;font-size:17px;\">grazing</div>", "<div style=\"font-family:Cambria;font-size:17px;\">pests</div>", "<div style=\"font-family:Cambria;font-size:17px;\">fire</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">In the savannah, there is the presence of extremes of temperature which ranges from 21<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">o</span>C to 30<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">o</span>C. The trees in the savannah have large trunks to store water during drought.Hence, trees in the savanna usually have tick, scarred barks due to the effect of the drought</div>", "topic": "PRATICAL GEOGRAPHY II : VEGETATION"}, {"id": "objective>Geography>1995>12", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Which of the following characteristics clearly distinguishes a mature soil from a juvenile one?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">Sand fraction greater than 50%</div>", "<div style=\"font-family:Cambria;font-size:17px;\"> Low nitrogen content</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Well-developed profile</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Soil pH-value of approximately 6.5</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Mature soils are those which are old and well developed.They have passed through the major developmental phases while juvenile soils are those which are new and not fully developed</div>", "topic": "PRATICAL GEOGRAPHY II : SOILS"}, {"id": "objective>Geography>1995>13", "question": "<div style=\"font-family:Cambria;font-size:17px;\">A tropical tree that is often grown in pure stands is the?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">mahogany</div>", "<div style=\"font-family:Cambria;font-size:17px;\">teak</div>", "<div style=\"font-family:Cambria;font-size:17px;\">ebony</div>", "<div style=\"font-family:Cambria;font-size:17px;\">ironwood</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Pure stand means a population of plants consisting exclusively or largely of members of one specie,variety or type. Mahogany trees grow in the tropical moist decidous forest and tropical rain forest in the west indies, the west coast of Africa ,southern Mexico,Central America and Suth America. It usually grows in pure stands.</div>", "topic": "PRATICAL GEOGRAPHY II : VEGETATION"}, {"id": "objective>Geography>1995>14", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Tropical rain forest are important to the functioning of the earth's environment because they are large reservoirs of?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\"> oxygen, mositure and biodiversity</div>", "<div style=\"font-family:Cambria;font-size:17px;\">timber, wildlife and virgin soils</div>", "<div style=\"font-family:Cambria;font-size:17px;\">water, energy and mineral resources</div>", "<div style=\"font-family:Cambria;font-size:17px;\">food, fibre and medicinal plants</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The tropical rainforest is important in its provision of hardwood(timber) for building,furniture and other construction activities.Also, the tropical rainforest provides a zone for hunting of wild animals.Its soil is usually virgin i.e most of them have never been cultivated.</div>", "topic": "PRATICAL GEOGRAPHY II : VEGETATION"}, {"id": "objective>Geography>1995>15", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The portion of the earth that contains life is the?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">atmosphere</div>", "<div style=\"font-family:Cambria;font-size:17px;\">hydrosphere</div>", "<div style=\"font-family:Cambria;font-size:17px;\">lithosphere</div>", "<div style=\"font-family:Cambria;font-size:17px;\">biosphere</div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The biosphere is the zone of the earth occupied by living organisms. It includes organisms like plants, animals and micro-organism</div>", "topic": "HUMAN GEOGRAPHY : POPULATION"}, {"id": "objective>Geography>1995>16", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Which of the following regions has low population density?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">The Nile Basin</div>", "<div style=\"font-family:Cambria;font-size:17px;\">The Ganges Basin</div>", "<div style=\"font-family:Cambria;font-size:17px;\"> North Eastern U.S.A</div>", "<div style=\"font-family:Cambria;font-size:17px;\">The Zarie Basin</div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The Nile Basin has a population density of 2000 persons per square km, the Ganges Basin has a population density of 390 persons per square km, North Eastern U.S.A has a population density of 1,253 persons per square km and the The Zarie Basin has a population density of 30 persons per square km. Hence, The Zarie Basin has the lowwest population density</div>", "topic": "HUMAN GEOGRAPHY : POPULATION"}, {"id": "objective>Geography>1995>17", "question": "<div style=\"font-family:Cambria;font-size:17px;\">One of the tertiary services in an urban centre is?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">food processing</div>", "<div style=\"font-family:Cambria;font-size:17px;\">petrol retailing</div>", "<div style=\"font-family:Cambria;font-size:17px;\"> car assembling</div>", "<div style=\"font-family:Cambria;font-size:17px;\">market gardening</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The tertiary services in an urban centre involves distribution services.Of all the listed options, only petrol retailing involves distribution.Hence, petrol retailing is a tertiary service in urban centres</div>", "topic": "HUMAN GEOGRAPHY : SELECTED ECONOMIC ACTIVITIES"}, {"id": "objective>Geography>1995>18", "question": "<div style=\"font-family:Cambria;font-size:17px;\">A city may be differentiated from a rural settlement by considering its?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">population size and age structure</div>", "<div style=\"font-family:Cambria;font-size:17px;\">skilled and unskilled manpower</div>", "<div style=\"font-family:Cambria;font-size:17px;\">population and functions</div>", "<div style=\"font-family:Cambria;font-size:17px;\">road network and industral estates</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">A city is a large town with greater number of people than town. A rural settlement is a relatively small area with socially homogenous people that know one another very well. A city is mainly involved in secondary and tertiary activities while a rural settlement is invoved in primary activities such as farming. Hence, a city is differentiated from a rural settlement by considering its population and functions </div>", "topic": "HUMAN GEOGRAPHY : SETTLEMENT"}, {"id": "objective>Geography>1995>19", "question": "<div style=\"font-family:Cambria;font-size:17px;\">A settlement located at a place on a plain where several roads meet is likely to be nucleated and?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">star-shaped</div>", "<div style=\"font-family:Cambria;font-size:17px;\">circular</div>", "<div style=\"font-family:Cambria;font-size:17px;\">linear</div>", "<div style=\"font-family:Cambria;font-size:17px;\">rectangular</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">A starshaped settlement is found around the points where several roads cross each other making a star shape. A settlement located at a place on a plain where several roads meet is likely to be nucleated and star-shaped</div>", "topic": "HUMAN GEOGRAPHY : SETTLEMENT"}, {"id": "objective>Geography>1995>20", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Malaysia, Bolivia and Nigeria are noted for the production of?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">coal</div>", "<div style=\"font-family:Cambria;font-size:17px;\">natural gas</div>", "<div style=\"font-family:Cambria;font-size:17px;\">petroleum</div>", "<div style=\"font-family:Cambria;font-size:17px;\">tin</div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Malaysia, Bolivia and Nigeria are noted for the production of tin.Malaysia's production of tin amounted to approximately 3.2 thousand metric tons. Bolvia ranks the sixth largest producer of tin with about 327,200 tonnes produced. Nigeria has a total production volume of tin approximately 5.9 thousand metric tons</div>", "topic": "HUMAN GEOGRAPHY : SELECTED ECONOMIC ACTIVITIES"}, {"id": "objective>Geography>1995>21", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Cattle are sent from the Great Plains of U.S.A for fattening and sale in the?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">corn belt</div>", "<div style=\"font-family:Cambria;font-size:17px;\">wheat belt</div>", "<div style=\"font-family:Cambria;font-size:17px;\">industrial North East</div>", "<div style=\"font-family:Cambria;font-size:17px;\">South East</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The livestock industries are a major contributor of the north eastern United States. Dairy production is a major contributor to the agricultural economy of the north eastern US.So, cattle are sent from the Great plains of USA for fattening and sale in the Industrial NorthEast</div>", "topic": "HUMAN GEOGRAPHY : SELECTED ECONOMIC ACTIVITIES"}, {"id": "objective>Geography>1995>22", "question": "<div style=\"font-family:Cambria;font-size:17px;\">An industry in which a large proportion of the weight of the inputs is lost during processing is likely to locate near the source of?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">labour</div>", "<div style=\"font-family:Cambria;font-size:17px;\">energy</div>", "<div style=\"font-family:Cambria;font-size:17px;\">capital</div>", "<div style=\"font-family:Cambria;font-size:17px;\">raw materials</div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">To avoid loss in a large proportion of the weights of the inputs, an industry has to be located close to the source of its raw materials</div>", "topic": "HUMAN GEOGRAPHY : SELECTED ECONOMIC ACTIVITIES"}, {"id": "objective>Geography>1995>23", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Petroleum is the most widely used source of power because to the bottom of an oil well?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">is relatively cheap to mine</div>", "<div style=\"font-family:Cambria;font-size:17px;\">is very easily transported</div>", "<div style=\"font-family:Cambria;font-size:17px;\">yields many types of fuel</div>", "<div style=\"font-family:Cambria;font-size:17px;\">burns easily</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Petroleum is widely used as power source due to several of its fractions found in oil wells such as diesel fuel,heating oil,jet fuel,lubricating oils,kerosene,butane,liquefied natural gas etc</div>", "topic": "PRATICAL GEOGRAPHY II : ENVIRONMENTAL RESOURCES"}, {"id": "objective>Geography>1995>24", "question": "<div style=\"font-family:Cambria;font-size:17px;\">In what order do the following occur from the surface to the bottom of an oil well?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">Oil, water, gas</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Gas, oil, water</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Oil, gas, water</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Gas, water, oil</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">An oil well is a boring in the Earth that is defined to bring petroleum oil hydrocarbons to the surface.When drilling occurs in an oil reserve,gas,oil and water occur in this order from the surface to the bottom of the oil well.</div>", "topic": "PRATICAL GEOGRAPHY II : ENVIRONMENTAL RESOURCES"}, {"id": "objective>Geography>1995>25", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The world's leading entrepots include?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\"> Panama, Gilbraltar and Suez</div>", "<div style=\"font-family:Cambria;font-size:17px;\">New York, Calais and Harmburg</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Bombay. Syndey and Rio de Janeiro</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Hong Kong, London and Rotterdam</div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Hong Kong, London and Rotterdam are spatial zones through which international commercial flows of trade and credit are mediated. They are strategic locations for entrepot trade.</div>", "topic": "HUMAN GEOGRAPHY : SELECTED ECONOMIC ACTIVITIES"}, {"id": "objective>Geography>1995>26", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The main commodities shipped on the trans-Pacific Sea route include?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">wheat and iron ore</div>", "<div style=\"font-family:Cambria;font-size:17px;\">manufactured goods and crude oil</div>", "<div style=\"font-family:Cambria;font-size:17px;\"> crude oil and coal</div>", "<div style=\"font-family:Cambria;font-size:17px;\">wheat and manufactured goods</div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The trans-pacific route is the longest in distance and has increasing significance in view of the rapid economic development of west -USA,China,Japan,Australia etc. Wheat and manufactured goods are the main commodities shipped on the trans-pacific route.</div>", "topic": "HUMAN GEOGRAPHY : SELECTED ECONOMIC ACTIVITIES"}, {"id": "objective>Geography>1995>27", "question": "<div style=\"font-family:Cambria;font-size:17px;\">On which of the following sea is coffee an important commodity?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">Rio de Janeiro to New York</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Sydney to Singapore</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Durban to Calcutta</div>", "<div style=\"font-family:Cambria;font-size:17px;\">San Francisco to Yokohama</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">As an international commodity, coffee first expanded into the Paraiba river valley north and west from the port city of Rio de Janeiro, Brazil. So, coffee is an important commodity in the Rio de Janeiro to New York sea Route</div>", "topic": "REGIONAL GEOGRAPHY : BROAD OUTLINE OF NIGERIA"}, {"id": "objective>Geography>1995>28", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The factor controlling the onset and cessation of the rainy season in Nigeria is the?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">latitudinal extent of the country</div>", "<div style=\"font-family:Cambria;font-size:17px;\">presence of plateaux and highlands</div>", "<div style=\"font-family:Cambria;font-size:17px;\">movement of the Inter Tropical Discontinuity</div>", "<div style=\"font-family:Cambria;font-size:17px;\">presence of the warm Guniea Current</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The raining season starts and ends as a result of the movement of the inter Tropical Discontinuity.The inter Tropical Discontinuity(ITD) migrates north and south of Nigeria bringing rainfall or dryness to different areas of the country at different times of the year.</div>", "topic": "REGIONAL GEOGRAPHY : BROAD OUTLINE OF NIGERIA"}, {"id": "objective>Geography>1995>29", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Which of the following power plants in Nigeria is paired with the wrong energy source?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">Oji-coal</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Egbin-gas</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Kaniji-water</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Afam-sun</div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The Afam IV power station is a 450-megawatt natural gas power stattion in Rivers state, Nigeria. It is not powered by the sun rather by gas</div>", "topic": "REGIONAL GEOGRAPHY : BROAD OUTLINE OF NIGERIA"}, {"id": "objective>Geography>1995>30", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Which of the following geographical region of Nigeria is generally flat and dotted with granitic hills?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">Chad Basin</div>", "<div style=\"font-family:Cambria;font-size:17px;\">North Cental Highlands</div>", "<div style=\"font-family:Cambria;font-size:17px;\">South Eastern HIghlands</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Cross River basin</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The South Eastern Highlands of Nigeria is located at the foot of flat and dotted granitic hills and valleys. They also have base complex rocks</div>", "topic": "REGIONAL GEOGRAPHY : GEOGRAPHICAL REGIONS OF NIGERIA"}, {"id": "objective>Geography>1995>31", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Which of the following best explains the growth of Lagos? i. Infrastructural facilities. ii. Early contact with the outside world. iii. Being the former seat of the government. iv. Extensive land for development.</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">i and ii</div>", "<div style=\"font-family:Cambria;font-size:17px;\">i and iv</div>", "<div style=\"font-family:Cambria;font-size:17px;\">i, ii and iii</div>", "<div style=\"font-family:Cambria;font-size:17px;\">ii, iii and iv</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Lagos does not possess a widespread of land.Its growth is best explained by Infrastructural facilities,Early contact with the outside world and Being the former seat of the government</div>", "topic": "HUMAN GEOGRAPHY : SETTLEMENT"}, {"id": "objective>Geography>1995>32", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The ecological zone with the largest hectarage of irrigated land in Nigeria is the?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\"> rain forest</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Guniea savannah</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Sudan savannah</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Sahel savannah</div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Scanty and unreliable rainfall in the Sahel Savanna makes farming difficult. The sahel agricultural possesses a significant irrigation potential. The results for total irrigation potential potential in the Sahel savannah are in the range of 0.6-0.9M Hectares. The sahel savannah zone is the zone with the largest hectarage of irrigated land.</div>", "topic": "REGIONAL GEOGRAPHY : GEOGRAPHICAL REGIONS OF NIGERIA"}, {"id": "objective>Geography>1995>33", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The hydrographic centre in Nigeria is?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">Jos Plateau</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Udi Hills</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Mambilla Plateau</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Mandara Mountains</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">An hydrographic centre is a centre that measures and describes the physical features of bodies of water.Such features are the water depth, the shape of the seafloor and coastline etc.A major hydrographic centre in Nigeria is the Udi Hill</div>", "topic": "REGIONAL GEOGRAPHY : BROAD OUTLINE OF NIGERIA"}, {"id": "objective>Geography>1995>34", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Which of the following BEST explains the relatively low population density of the middle belt of Nigeria?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">thick forest</div>", "<div style=\"font-family:Cambria;font-size:17px;\">rugged d landscape</div>", "<div style=\"font-family:Cambria;font-size:17px;\">swampy river troughs</div>", "<div style=\"font-family:Cambria;font-size:17px;\">historical factors</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The middle belt of Nigeria contains salt water swamp or mangrove swamp as a result of large amount of mangrove in the area. As a result of the swampy river trough in the middle belt of Nigeria, it has a relatively low population density.</div>", "topic": "REGIONAL GEOGRAPHY : BROAD OUTLINE OF NIGERIA"}, {"id": "objective>Geography>1995>35", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The common exotic tree species planted in the northern savannah are?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">teak and gmelina</div>", "<div style=\"font-family:Cambria;font-size:17px;\">baobab and acacia</div>", "<div style=\"font-family:Cambria;font-size:17px;\">mango annd locust bean</div>", "<div style=\"font-family:Cambria;font-size:17px;\">neem and euclyptus</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The major popular trees in the savannah include include Shea butter, baobab and acacia. The Shea butter, baobab and acacia trees have large trunks and their branches spread out like canopies.</div>", "topic": "REGIONAL GEOGRAPHY : AFRICA ON BROAD OUTLINE"}, {"id": "objective>Geography>1995>36", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The major factors accounting for increasing desertification in the West Africa Sahel are drought?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">overgrazing and overcultivation</div>", "<div style=\"font-family:Cambria;font-size:17px;\">locusts and queller birds</div>", "<div style=\"font-family:Cambria;font-size:17px;\"> urbanization and fuel wood exploitation</div>", "<div style=\"font-family:Cambria;font-size:17px;\">harmattan and sand dunes</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The increasing desertification in the sahel of West Africa occurs as a result of human activities such as overgrazing,deforestation,surface land mining,overcultivation ad poor irrigation techniques during a natural time of drought.</div>", "topic": "REGIONAL GEOGRAPHY : AFRICA ON BROAD OUTLINE"}, {"id": "objective>Geography>1995>37", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Which of these West Africa countries is known for the mining of phosphates?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">Niger</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Nigeria</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Togo</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Liberia</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The mining industry of Togo is centered mainly around the extraction of phosphates, ranking it 19th in world production. Other minerals extracted are diamond,gold and limestone. More mineral identified  but yet to be brought into production mode are manganese,bauxite,gypsum,iron ore,marble, nitile and zinc </div>", "topic": "REGIONAL GEOGRAPHY : MINERAL EXPLOITATION"}, {"id": "objective>Geography>1995>38", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Use the map below to answer the question <br/> <img src=\"data:image/png;base64,\" style=\"position:relative;max-width:100%;\"/> <br/>  <br/> The river marked S has been dammed for Hydroelectric power generation at </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">Shiroro gorge</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Jebba</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Goronyo</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Kurra falls</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The shiroro gorge is found on River Kaduna.According to the map, the river marked S has been dammed for Hydroelectric power registration at the Shiroro gorge</div>", "topic": "PRATICAL GEOGRAPHY II : WATER BODIES"}, {"id": "objective>Geography>1995>39", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The densely populated areas of South East Asia are also areas of</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">Massive rice importations</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Intensive peasant farming</div>", "<div style=\"font-family:Cambria;font-size:17px;\"> Low birth and death rates</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Fast-growing heavy industries</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The densely populated areas of south east Asia are involved in intensive peasant farming centered around rice cultivation. Rice exportation is the main agricultural production activity accounting for a greater share of gross production value than any other single commodity.</div>", "topic": "HUMAN GEOGRAPHY : POPULATION"}, {"id": "objective>Geography>1995>40", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Which of the following is responsible for the formation of block mountains?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">Faulting</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Folding</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Sedimentation</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Deposition</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Block mountains is formed as a result of earth cracks due to faulting. Faulting may result from tension forces or compressional forces.</div>", "topic": "PRATICAL GEOGRAPHY II : LANDFORMS"}, {"id": "objective>Geography>1995>41", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Use the map below to answer the question <br/> <img src=\"data:image/png;base64,\" style=\"position:relative;max-width:100%;\"/> <br/>  <br/> The shaded areas numbered 1-6 are </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">Biological deserts of the world</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Major areas of nomadic grazing</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Sparsely populated regions of the world</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Mountains of the world</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">According to the map, the shaded areas numbered 1-6 are regions of the world that contain few people i.e regions that are sparsely populated.</div>", "topic": "PRATICAL GEOGRAPHY II : VEGETATION"}, {"id": "objective>Geography>1995>42", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Use the map below to answer the question <br/> <img src=\"data:image/png;base64,\" style=\"position:relative;max-width:100%;\"/> <br/> The stippled coastal seas are the world's major areas of</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">Fish farming</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Whaling</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Deep sea fishing</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Commercial fishing</div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Commercial fishing is the taking of fish and other sea food and resources from oceans, rivers and seas for the purpose of marketing them.Commercial fishing can be performed in the areas of stippled coastal seas</div>", "topic": "PRATICAL GEOGRAPHY II : WATER BODIES"}, {"id": "objective>Geography>1995>43", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Use the map below to answer the question <br/> <img src=\"data:image/png;base64,\" style=\"position:relative;max-width:100%;\"/> <br/> The major exports from the pacific country shown to the regions indicted by arrows are</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">Coal, gas and crude oil</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Automobiles, electronics and manpower</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Fish, electronics and manpower</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Automobiles, aircraft and iron ore</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The major export commodities are automobiles e.g cars, buses etc, electronics e.g computers, smart televisions etc and manpower</div>", "topic": "HUMAN GEOGRAPHY : SELECTED ECONOMIC ACTIVITIES"}, {"id": "objective>Geography>1995>44", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Use the map below to answer the question <br/> <img src=\"data:image/png;base64,\" style=\"position:relative;max-width:100%;\"/> <br/> Which of the areas marked F,G,H,J and K are well known for rearing of cattle, sheep and pigs?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">F,G,H</div>", "<div style=\"font-family:Cambria;font-size:17px;\">F,G,J</div>", "<div style=\"font-family:Cambria;font-size:17px;\">F,J,K</div>", "<div style=\"font-family:Cambria;font-size:17px;\">G,H,J</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Area F is notable for rearing of cattle, Area J is notable for rearing of sheeps and Area K is notable for rearing of pigs</div>", "topic": "HUMAN GEOGRAPHY : SELECTED ECONOMIC ACTIVITIES"}, {"id": "objective>Geography>1995>45", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Use the map below to answer the question <br/> <img src=\"data:image/png;base64,\" style=\"position:relative;max-width:100%;\"/> <br/> The areas marked P are noted for the production of</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">Iron ore</div>", "<div style=\"font-family:Cambria;font-size:17px;\">crude oil</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Sugarcane</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Wheat</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The areas marked P are noted for the production of sugarcane due to its moisture-retaining soil and well drained loamy soil with neutral soil reaction.</div>", "topic": "PRATICAL GEOGRAPHY I : MAP READING AND INTERPRETATION"}, {"id": "objective>Geography>1995>46", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Use the map below to answer the question <br/> <img src=\"data:image/png;base64,\" style=\"position:relative;max-width:100%;\"/> <br/>  <br/> What is the approximate length of the broad and shallow of River Amy? </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">5.3km</div>", "<div style=\"font-family:Cambria;font-size:17px;\">7.3km</div>", "<div style=\"font-family:Cambria;font-size:17px;\">12.8km</div>", "<div style=\"font-family:Cambria;font-size:17px;\">15.0km</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The approximate length of the broad and shallow of River Amy is calculated from the map as 7.3km.</div>", "topic": "PRATICAL GEOGRAPHY I : MAP READING AND INTERPRETATION"}, {"id": "objective>Geography>1995>47", "question": "<div style=\"font-family:Cambria;font-size:17px;\"> Use the map below to answer the question <br/> <img src=\"data:image/png;base64,\" style=\"position:relative;max-width:100%;\"/> <br/> The deposition along the channel of River Amy to the south west is probably due to the</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">A construction of a dam across the river</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Fall in gradient at the base of the hill</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Marked increase in the rivers erosive power</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Channelization of the river course</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Due to the fall in gradient at the base of the hill, there is deposition along the channel of River Amy to the south west. </div>", "topic": "PRATICAL GEOGRAPHY II : WATER BODIES"}, {"id": "objective>Geography>1995>48", "question": "<div style=\"font-family:Cambria;font-size:17px;\"> Use the map below to answer the question <br/> <img src=\"data:image/png;base64,\" style=\"position:relative;max-width:100%;\"/> <br/> The topography of the area may be be described as</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">A plateau with a broad footslope plain</div>", "<div style=\"font-family:Cambria;font-size:17px;\">A flood plain with a monodnock</div>", "<div style=\"font-family:Cambria;font-size:17px;\">An undulating high plain with occasional inselbergs</div>", "<div style=\"font-family:Cambria;font-size:17px;\">A rugged hill with a pediment slope</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The topography of the area is that of an isolated hill or erosion-resistant rock. It is a flood plain with a monodnock.</div>", "topic": "PRATICAL GEOGRAPHY II : LANDFORMS"}, {"id": "objective>Geography>1995>49", "question": "<div style=\"font-family:Cambria;font-size:17px;\"> Use the map below to answer the question <br/> <img src=\"data:image/png;base64,\" style=\"position:relative;max-width:100%;\"/> <br/> The pattern of settlement distribution in the area is BEST explained in terms of the</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">Drainage</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Slope</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Vegetation</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Soils</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The pattern of settlement distribution as shown by the map is best explained in terms of the slope or gradient of the area.</div>", "topic": "HUMAN GEOGRAPHY : SETTLEMENT"}, {"id": "objective>Geography>1995>50", "question": "<div style=\"font-family:Cambria;font-size:17px;\"> Use the map below to answer the question <br/> <img src=\"data:image/png;base64,\" style=\"position:relative;max-width:100%;\"/> <br/> The woodland vegetation in the area is probably due to the</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">Low level of lumbering activity</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Humus rich soils</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Abundant orographic rainfall</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Steep gradient precluding cultivation</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">As a result of a well-drained loamy soil with neutral soil reaction and a great humus content, there is presence of woodland vegetation in the area.</div>", "topic": "PRATICAL GEOGRAPHY II : VEGETATION"}];
